import React from 'react';
import './About.css'; // Optional: Add some styling for this page

function About() {
  return (
    <div className="about-container">
      {/* Header for About Me Section */}
      <h1>About Me</h1>

      {/* Paragraphs with content */}
      <p>

      Hello! I’m Shreya, a passionate Web Developer dedicated to crafting seamless and engaging web experiences. With a solid background in HTML, CSS, JavaScript, and modern Front-End frameworks, I thrive on turning complex challenges into intuitive and functional designs. I started my journey by pursuing a Master's degree in Computer Science from New Mexico State University - Main Campus.      </p>



      <p>
      Over the years, I’ve had the privilege of working on diverse projects that showcase my ability to blend creativity with technical skill. From interactive user interfaces to responsive layouts, I take pride in delivering high-quality solutions that meet user needs. I thrive on weaving together aesthetics and functionality, crafting solutions that not only meet user needs but also spark delight and curiosity.
      </p>
    </div>
  );
}

export default About;
